Here's an example implementation of a Shape class using polymorphism in C++:

```
#include <iostream>
#include <cmath>

using namespace std;

class Shape {
public:
    virtual double area() = 0;
};

class Rectangle : public Shape {
private:
    double width, height;
public:
    Rectangle(double w, double h): width(w), height(h) {}
    double area() {
        return width * height;
    }
};

class Circle : public Shape {
private:
    double radius;
public:
    Circle(double r) : radius(r) {}
    double area() {
        return M_PI * pow(radius, 2);
    }
};

int main() {
